/// <summary>
/// Extensión de los métodos del formulario <c>DirPartyQuickCreateForm</c> para el modelo ETGSPAIN.
/// </summary>
[ExtensionOf(formStr(DirPartyQuickCreateForm))]
final class DirPartyQuickCreateForm_ETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extensión del método <c>init</c> para hacer obligatorio el campo <c>ETGSPAINSalesPurchPartyCountry</c>.
/// </summary>
public void init()
{
    next init();

    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    if (currentCompanyIsSpanishCompany == NoYes::Yes)
    {
        Args elementArgs = this.args();

        if (elementArgs)
        {
            callerRecord = elementArgs.record();

            if (callerRecord.TableId == tableNum(CustTable))
            {
                this.dataSource("DirPartyEntity").object(fieldNum(CustTable, ETGSPAINSalesPurchPartyCountry)).mandatory(true);
            }
        }
    }
}
